using System;
using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.InputSystem;
using UnityEngine.UI;

/// <summary>
/// Tarefa #35 — UI da Loja (Sistema de Loja): painel com duas listas,
/// "Comprar" (itens da ShopData, respeitando preços/promoções/horários) e
/// "Vender" (itens "sellable" do inventário do jogador, recomprados pelo
/// vendedor se ShopData.merchantBuysItems estiver activo — sempre por
/// ShopData.buybackMultiplier × ItemData.sellPrice, por omissão metade).
///
/// Aberta por <see cref="Action_OpenShop"/> (Eventos de NPC) via
/// <see cref="OpenAndWait"/>, que pausa o jogo (GamePauseUtil) enquanto o
/// painel estiver aberto — mesma lógica do diálogo/menu de escolhas.
///
/// Montagem no Editor:
/// - "panelRoot": GameObject raiz do painel (activado/desactivado ao abrir/fechar).
/// - "buyContainer"/"buyRowPrefab": lista de compra (ShopBuyRowUI).
/// - "sellContainer"/"sellRowPrefab": lista de venda (ShopSellRowUI) — só
///   aparece se a loja actual tiver "merchantBuysItems" activo.
/// - "allSellableItems": todos os ItemData do jogo com "sellable" = true que
///   podem aparecer na lista de venda (filtra automaticamente pelo
///   inventário do jogador — só mostra os que ele possui).
/// - "closeButton": botão "Fechar" (opcional — Esc/B do gamepad também fecham).
/// </summary>
public class ShopUI : MonoBehaviour
{
    public static ShopUI Instance { get; private set; }

    [Header("Framework")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private TMP_Text shopNameText;
    [SerializeField] private Button closeButton;

    [Header("Sementes")]
    [SerializeField] private TMP_Text sementesText;
    [SerializeField] private string sementesFormat = "Sementes: {0}";

    [Header("Comprar")]
    [SerializeField] private Transform buyContainer;
    [SerializeField] private ShopBuyRowUI buyRowPrefab;
    [SerializeField] private GameObject buyEmptyState;
    [SerializeField] private string buyEmptyText = "Sem itens à venda agora.";

    [Header("Vender")]
    [SerializeField] private GameObject sellSectionRoot;
    [SerializeField] private Transform sellContainer;
    [SerializeField] private ShopSellRowUI sellRowPrefab;
    [SerializeField] private GameObject sellEmptyState;
    [SerializeField] private string sellEmptyText = "Não tens nada para vender.";

    [Tooltip("Todos os ItemData do jogo com 'sellable' = true candidatos a aparecer na lista de venda (filtrados pelo inventário do jogador).")]
    [SerializeField] private List<ItemData> allSellableItems = new List<ItemData>();

    [Header("Sons")]
    [SerializeField] private AudioClip buySfx;
    [SerializeField] private AudioClip sellSfx;
    [SerializeField] private AudioClip errorSfx;

    private ShopData currentShop;
    private bool closeRequested;

    private readonly List<GameObject> spawnedBuy = new List<GameObject>();
    private readonly List<GameObject> spawnedSell = new List<GameObject>();

    private void Awake()
    {
        Instance = this;
        if (panelRoot != null) panelRoot.SetActive(false);
    }

    private void OnEnable()
    {
        if (closeButton != null) closeButton.onClick.AddListener(RequestClose);

        var progress = PlayerProgress.Instance;
        if (progress != null) progress.SeedsChanged += HandleSeedsChanged;
    }

    private void OnDisable()
    {
        if (closeButton != null) closeButton.onClick.RemoveListener(RequestClose);

        var progress = PlayerProgress.Instance;
        if (progress != null) progress.SeedsChanged -= HandleSeedsChanged;
    }

    /// <summary>Abre a loja "shop" e só devolve o controlo quando o jogador a fechar (botão "Fechar", Esc ou B/Círculo do gamepad).</summary>
    public IEnumerator OpenAndWait(ShopData shop)
    {
        if (shop == null) yield break;

        currentShop = shop;
        closeRequested = false;

        GamePauseUtil.Pause();

        if (panelRoot != null) panelRoot.SetActive(true);
        if (shopNameText != null) shopNameText.text = shop.shopName;

        Refresh();

        while (!closeRequested)
        {
            PollCloseInput();
            yield return null;
        }

        ClearSpawned();
        if (panelRoot != null) panelRoot.SetActive(false);

        GamePauseUtil.Resume();
        currentShop = null;
    }

    /// <summary>Pede o fecho da loja no fim do frame actual. Pode ser ligado a um botão "Fechar".</summary>
    public void RequestClose() => closeRequested = true;

    private void PollCloseInput()
    {
        var keyboard = Keyboard.current;
        if (keyboard != null && keyboard.escapeKey.wasPressedThisFrame) RequestClose();

        var gamepad = Gamepad.current;
        if (gamepad != null && (gamepad.buttonEast.wasPressedThisFrame || gamepad.buttonSouth.wasPressedThisFrame))
        {
            // Só fecha com "Sul"/"A" se nenhum elemento estiver focado, para não
            // entrar em conflito com a confirmação de compra/venda dos botões.
            bool nothingSelected = EventSystem.current == null || EventSystem.current.currentSelectedGameObject == null;
            if (gamepad.buttonEast.wasPressedThisFrame || nothingSelected) RequestClose();
        }
    }

    // ==================== Refresh ====================

    private void Refresh()
    {
        ClearSpawned();
        RefreshSementes();
        RefreshBuyList();
        RefreshSellList();

        if (EventSystem.current != null && spawnedBuy.Count > 0)
            EventSystem.current.SetSelectedGameObject(spawnedBuy[0]);
    }

    private void RefreshSementes()
    {
        if (sementesText == null) return;

        int sementes = PlayerProgress.Instance != null ? PlayerProgress.Instance.sementes : 0;
        sementesText.text = string.Format(sementesFormat, sementes);
    }

    private void RefreshBuyList()
    {
        if (currentShop == null || buyContainer == null || buyRowPrefab == null) return;

        var progress = PlayerProgress.Instance;

        // Itens normais primeiro, depois itens de compra única já adquiridos
        // (aparecem no final, cinza/bloqueados — GDD: "itens bloqueados ficam
        // no final da lista para não atrapalhar o foco dos itens importantes").
        var normalEntries    = new System.Collections.Generic.List<ShopEntry>();
        var onceOwnedEntries = new System.Collections.Generic.List<ShopEntry>();

        foreach (var entry in currentShop.entries)
        {
            if (entry == null || entry.item == null) continue;
            if (!entry.IsAvailableNow()) continue;

            bool isOnce    = entry.item.onlyBuyOnce;
            bool alreadyHad = isOnce && progress != null && progress.HasCollectedSpecialItem(entry.item.itemId);

            if (isOnce && alreadyHad)
                onceOwnedEntries.Add(entry);
            else
                normalEntries.Add(entry);
        }

        // Exibir itens normais.
        foreach (var entry in normalEntries)
        {
            var row = Instantiate(buyRowPrefab, buyContainer);
            row.gameObject.SetActive(true);
            row.Setup(entry, Buy);
            spawnedBuy.Add(row.gameObject);
        }

        // Exibir itens de compra única já adquiridos (bloqueados, no final).
        foreach (var entry in onceOwnedEntries)
        {
            var row = Instantiate(buyRowPrefab, buyContainer);
            row.gameObject.SetActive(true);
            row.SetupLocked(entry); // visual cinza, sem callback de compra.
            spawnedBuy.Add(row.gameObject);
        }

        if (buyEmptyState != null)
        {
            bool empty = spawnedBuy.Count == 0;
            buyEmptyState.SetActive(empty);

            if (empty)
            {
                var label = buyEmptyState.GetComponentInChildren<TMP_Text>();
                if (label != null) label.text = buyEmptyText;
            }
        }
    }

    private void RefreshSellList()
    {
        bool canSell = currentShop != null && currentShop.merchantBuysItems;
        if (sellSectionRoot != null) sellSectionRoot.SetActive(canSell);
        if (!canSell || sellContainer == null || sellRowPrefab == null) return;

        var progress = PlayerProgress.Instance;

        foreach (var item in allSellableItems)
        {
            if (item == null || !item.sellable) continue;

            int quantity = progress != null ? progress.GetItemQuantity(item) : 0;
            if (quantity <= 0) continue;

            int price = currentShop.GetBuybackPrice(item);

            var row = Instantiate(sellRowPrefab, sellContainer);
            row.gameObject.SetActive(true);
            row.Setup(item, quantity, price, Sell);
            spawnedSell.Add(row.gameObject);
        }

        if (sellEmptyState != null)
        {
            bool empty = spawnedSell.Count == 0;
            sellEmptyState.SetActive(empty);

            if (empty)
            {
                var label = sellEmptyState.GetComponentInChildren<TMP_Text>();
                if (label != null) label.text = sellEmptyText;
            }
        }
    }

    private void ClearSpawned()
    {
        foreach (var go in spawnedBuy)
            if (go != null) Destroy(go);
        spawnedBuy.Clear();

        foreach (var go in spawnedSell)
            if (go != null) Destroy(go);
        spawnedSell.Clear();
    }

    // ==================== Transacções ====================

    private void Buy(ShopEntry entry)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || entry == null || entry.item == null) return;

        // Bloqueio de compra única: não permite comprar de novo se já foi adquirido.
        if (entry.item.onlyBuyOnce && progress.HasCollectedSpecialItem(entry.item.itemId))
        {
            PlaySfx(errorSfx);
            return;
        }

        int price = entry.GetCurrentPrice();
        if (!progress.HasSementes(price))
        {
            PlaySfx(errorSfx);
            return;
        }

        progress.GiveSementes(-price);
        progress.AddItem(entry.item, 1);

        // Para itens de compra única: marcar como adquirido (usa o mesmo sistema
        // de collectedSpecialItemIds — requer savedAsCollected = true no ItemData).
        if (entry.item.onlyBuyOnce)
            progress.MarkSpecialItemCollected(entry.item.itemId);

        PlaySfx(buySfx);

        // Callback de pós-compra: permite que sistemas externos reajam à compra
        // de itens especiais (ex: abrir o Jukebox automaticamente na 1ª compra).
        OnItemPurchased?.Invoke(entry.item);

        Refresh();
    }

    /// <summary>
    /// Evento disparado após cada compra bem-sucedida na loja.
    /// Parâmetro: o <see cref="ItemData"/> comprado.
    /// Usado por sistemas externos (ex: JukeboxShopHandler) para reagir à
    /// compra de itens específicos (Jukebox, etc.) sem acoplar diretamente
    /// à ShopUI.
    /// </summary>
    public static event System.Action<ItemData> OnItemPurchased;

    // Task #11: limpa subscribers ao entrar em Play Mode sem Domain Reload
    // (mesmo padrão de PlayerLocator/GamePauseUtil/WheelTimeScaleUtil).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStaticEvents() => OnItemPurchased = null;

    private void Sell(ItemData item)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || currentShop == null || item == null) return;
        if (!currentShop.merchantBuysItems || !item.sellable) return;
        if (progress.GetItemQuantity(item) <= 0) return;

        int price = currentShop.GetBuybackPrice(item);

        progress.RemoveItem(item, 1);
        progress.GiveSementes(price);

        PlaySfx(sellSfx);
        Refresh();
    }

    // ==================== Helpers ====================

    private void HandleSeedsChanged(int sementes) => RefreshSementes();

    private void PlaySfx(AudioClip clip)
    {
        if (clip == null) return;
        if (AudioManager.Instance != null) AudioManager.Instance.PlaySE(clip);
        else AudioSource.PlayClipAtPoint(clip, transform.position);
    }
}

/// <summary>
/// Linha da lista "Comprar" da ShopUI: ícone, nome, preço (já com promoções
/// aplicadas) e indicador de promoção activa.
/// </summary>
public class ShopBuyRowUI : MonoBehaviour
{
    [SerializeField] private Image iconImage;
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private TMP_Text priceText;
    [SerializeField] private GameObject promoMarker;
    [Tooltip("Texto exibido no campo de preço quando o item já foi comprado (onlyBuyOnce). Ex: 'Adquirido'.")]
    [SerializeField] private string alreadyOwnedLabel = "Adquirido";

    private ShopEntry entry;
    private Action<ShopEntry> onBuy;

    public void Setup(ShopEntry entry, Action<ShopEntry> onBuy)
    {
        this.entry = entry;
        this.onBuy = onBuy;

        var item = entry.item;

        if (nameText != null) nameText.text = item.displayName;

        if (iconImage != null)
        {
            iconImage.sprite = item.icon;
            iconImage.enabled = item.icon != null;
        }

        if (priceText != null) priceText.text = entry.GetCurrentPrice().ToString();
        if (promoMarker != null) promoMarker.SetActive(entry.HasActivePromotion());

        var button = GetComponent<Button>();
        if (button != null)
        {
            button.onClick.RemoveAllListeners();
            button.onClick.AddListener(() => this.onBuy?.Invoke(this.entry));
            button.interactable = true;
        }
    }

    /// <summary>
    /// Configura a linha como "bloqueada" (item de compra única já adquirido):
    /// visual cinza, preço substituído por "Adquirido", botão não-interativo.
    /// </summary>
    public void SetupLocked(ShopEntry entry)
    {
        this.entry = entry;
        this.onBuy = null;

        var item = entry.item;

        if (nameText != null) nameText.text = item.displayName;

        if (iconImage != null)
        {
            iconImage.sprite = item.icon;
            iconImage.enabled = item.icon != null;
            // Tom cinza para indicar item já adquirido.
            iconImage.color = new Color(0.5f, 0.5f, 0.5f, 1f);
        }

        if (priceText != null) priceText.text = alreadyOwnedLabel;
        if (promoMarker != null) promoMarker.SetActive(false);

        var button = GetComponent<Button>();
        if (button != null)
        {
            button.onClick.RemoveAllListeners();
            button.interactable = false;
        }
    }
}

/// <summary>
/// Linha da lista "Vender" da ShopUI: ícone, nome, quantidade no inventário e
/// preço de recompra (ShopData.GetBuybackPrice).
/// </summary>
public class ShopSellRowUI : MonoBehaviour
{
    [SerializeField] private Image iconImage;
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private TMP_Text quantityText;
    [SerializeField] private TMP_Text priceText;

    private ItemData item;
    private Action<ItemData> onSell;

    public void Setup(ItemData item, int quantity, int buybackPrice, Action<ItemData> onSell)
    {
        this.item = item;
        this.onSell = onSell;

        if (nameText != null) nameText.text = item.displayName;
        if (quantityText != null) quantityText.text = quantity.ToString();
        if (priceText != null) priceText.text = buybackPrice.ToString();

        if (iconImage != null)
        {
            iconImage.sprite = item.icon;
            iconImage.enabled = item.icon != null;
        }

        var button = GetComponent<Button>();
        if (button != null)
        {
            button.onClick.RemoveAllListeners();
            button.onClick.AddListener(() => this.onSell?.Invoke(this.item));
        }
    }
}
